button {
width: 100%;
font-size: 1.2em;
outline: gray;
}

h4 {
    margin: 20px 0px
}
.steps .step {
    display: block;
    width: 100%;
    margin-bottom: 15px;
    text-align: center
}

.steps .step .step-icon-wrap {
    display: block;
    position: relative;
    width: 100%;
    height: 60px;
    text-align: center
}

.steps .step .step-icon-wrap::before,
.steps .step .step-icon-wrap::after {
    display: block;
    position: absolute;
    top: 50%;
    width: 50%;
    height: 3px;
    margin-top: -1px;
    background-color: #dae9e9;
    content: '';
    z-index: 1
}

.steps .step .step-icon-wrap::before {
    left: 0
}

.steps .step .step-icon-wrap::after {
    right: 0
}

.steps .step .step-icon {
    display: inline-block;
    position: relative;
    width: 60px;
    height: 60px;
    border-radius: 50%;
    background-color: #f5f5f5;
    font-size: 30px;
    line-height: 59px;
    z-index: 5
}

.steps .step .step-icon em {
    margin-left: 7px;
}

.steps .step .step-title {
    margin: 20px 0px;
    font-size: 18px;
    font-weight: bold
}

.steps .step:first-child .step-icon-wrap::before {
    display: none
}

.steps .step:last-child .step-icon-wrap::after {
    display: none
}

.steps .step.completed .step-icon-wrap::before,
.steps .step.completed .step-icon-wrap::after {
    background-color: #23497a;
}

.steps .step.completed .step-icon {
    color: #fff
}

.steps .step.current .step-icon-wrap::before,
.steps .step.current .step-icon-wrap::after {
    background-color: #124da8
}

.steps .step.current .step-icon {
    color: #fff;
}

[selector="nav-button"] button.btn.btn-primary {
    padding: 10px;
    font-size: 1.5em;
    font-weight: bold;
    text-transform: unset;
}

    .list {
        text-align: center;
    }
    .list ul {
        display: inline-block;
        margin: 0;
        padding: 0;
        /* For IE, the outcast */
        zoom:1;
        *display: inline;
    }

    .row.justify-content-md-center > .col-md-auto {
    width: 100%;
}
.row.justify-content-md-center > .col-md-auto button {
